module top_module(
    input [3:0] in,
    output [3:0] out
);// Module supplies
    supply1 VPWR;
    supply0 VGND;

    // Local signals
    wire [3:0] _shifted_temp;
    wire [3:0] shifted;

    // Assign the input to _shifted_temp
    assign _shifted_temp = in;

    // Shift the bits in _shifted_temp to the left by one position and assign the result to shifted
    assign shifted = {_shifted_temp[2:0], _shifted_temp[3]};

    // Assign shifted to the output
    assign out = shifted;

endmodule
